-- ============================================================
-- MATRIZ CONTABLE: ACTIVOS FIJOS (4 tipos de asiento)
-- Cuentas PCGE estándar; ajustar plan_contable_det_id según
-- el plan de cuentas vigente de cada empresa.
-- ============================================================

INSERT INTO contabilidad.matriz_contable (grupo_matriz_cntbl_id, codigo, descripcion, flag_estado)
SELECT g.id, v.codigo, v.descripcion, v.flag_estado
FROM (VALUES
    ('AF', 'AF-001',    'Asiento por depreciación mensual/anual de activos fijos',          '1'),
    ('AF', 'AF-002',    'Asiento por revaluación técnica o comercial de activos fijos',     '1'),
    ('AF', 'AF-003',    'Asiento por ajuste por inflación de activos fijos (NIC 29)',       '1'),
    ('AF', 'AF-004',    'Asiento por devengamiento mensual de primas de seguros de AF',    '1')
) AS v(modulo_codigo, codigo, descripcion, flag_estado)
JOIN contabilidad.grupo_matriz_cntbl g ON g.codigo = v.modulo_codigo
